Example: Using a Mutex
C++
#include <_mutex>
std::_mutex_sharedDataMutex;
int sharedData = 0;
void task1()
{
    std::lock_guard<std::_mutex> lock(sharedDataMutex);
    sharedData++;
}
void task2()
{
    std::lock_guard<std::_mutex> lock(sharedDataMutex);
    sharedData--;
}

